sql:
SELECT COUNT(neighborhood_id) AS total_explored
FROM neighborhood_explored
WHERE strategy_id = 1;

external_knowledge:
; Multiple strategies refer to at least two different strategies that have explored a neighborhood; 
; Average performance refers to the mean value of the metric_value for a given neighborhood, indicating how well strategies perform in that neighborhood; 
; Neighborhoods with no performance metrics have an average performance of 0.

sql:
SELECT neighborhood_name
FROM neighborhoods
ORDER BY neighborhood_name;
